class Solution:
    def numPermsDISequence(self, s: str) -> int:
        from itertools import permutations
        MOD = 10**9 + 7
        n = len(s)
        if n > 8:
            # brute force only feasible for small n; fall back to DP for larger
            dp = [1] * (n + 1)
            for i in range(1, n + 1):
                new_dp = [0] * (n + 1 - i)
                if s[i-1] == 'I':
                    pre = 0
                    for j in range(n + 1 - i):
                        pre = (pre + dp[j]) % MOD
                        new_dp[j] = pre
                else:
                    suf = 0
                    for j in range(n - i, -1, -1):
                        suf = (suf + dp[j+1]) % MOD
                        new_dp[j] = suf
                dp = new_dp
            return sum(dp) % MOD
        count = 0
        for perm in permutations(range(n + 1)):
            ok = True
            for i in range(n):
                if s[i] == 'D' and perm[i] <= perm[i+1]:
                    ok = False; break
                if s[i] == 'I' and perm[i] >= perm[i+1]:
                    ok = False; break
            if ok:
                count += 1
        return count % MOD

