var numPermsDISequence = function(s) {
    const MOD = 1000000007n;
    const n = s.length;
    let dp = new Array(n + 1).fill(1n);
    for (let i = 1; i <= n; i++) {
        const newDp = new Array(n + 1 - i).fill(0n);
        if (s[i - 1] === 'I') {
            let prefix = 0n;
            for (let j = 0; j < n + 1 - i; j++) {
                prefix = (prefix + dp[j]) % MOD;
                newDp[j] = prefix;
            }
        } else {
            let suffix = 0n;
            for (let j = n - i; j >= 0; j--) {
                suffix = (suffix + dp[j + 1]) % MOD;
                newDp[j] = suffix;
            }
        }
        dp = newDp;
    }
    return Number(dp.reduce((a, b) => (a + b) % MOD, 0n));
};
